    10→// making this static verbose function here
    11→// until we introduce a less confusing naming scheme
    12→// of jv_* API with regards to the memory management
    13→static double jv_number_get_value_and_consume(jv number) {
    14→  double value = jv_number_value(number);
    15→  jv_free(number);
    16→  return value;
    17→}
