    19→static jv parse_slice(jv j, jv slice, int* pstart, int* pend) {
    20→  // Array slices
    21→  jv start_jv = jv_object_get(jv_copy(slice), jv_string("start"));
    22→  jv end_jv = jv_object_get(slice, jv_string("end"));
    23→  if (jv_get_kind(start_jv) == JV_KIND_NULL) {
    24→    jv_free(start_jv);
    25→    start_jv = jv_number(0);
    26→  }
    27→  int len;
    28→  if (jv_get_kind(j) == JV_KIND_ARRAY) {
    29→    len = jv_array_length(j);
    30→  } else if (jv_get_kind(j) == JV_KIND_STRING) {
    31→    len = jv_string_length_codepoints(j);
    32→  } else {
    33→    /*
    34→     * XXX This should be dead code because callers shouldn't call this
    35→     * function if `j' is neither an array nor a string.
    36→     */
    37→    jv_free(j);
    38→    jv_free(start_jv);
    39→    jv_free(end_jv);
    40→    return jv_invalid_with_msg(jv_string("Only arrays and strings can be sliced"));
    41→  }
    42→  if (jv_get_kind(end_jv) == JV_KIND_NULL) {
    43→    jv_free(end_jv);
    44→    end_jv = jv_number(len);
    45→  }
    46→  if (jv_get_kind(start_jv) != JV_KIND_NUMBER ||
    47→      jv_get_kind(end_jv) != JV_KIND_NUMBER) {
    48→    jv_free(start_jv);
    49→    jv_free(end_jv);
    50→    return jv_invalid_with_msg(jv_string("Array/string slice indices must be integers"));
    51→  }
    52→
    53→  double dstart = jv_number_value(start_jv);
    54→  double dend = jv_number_value(end_jv);
    55→  int start, end;
    56→
    57→  jv_free(start_jv);
    58→  jv_free(end_jv);
    59→  if (isnan(dstart)) dstart = 0;
    60→  if (dstart < 0)    dstart += len;
    61→  if (dstart < 0)    dstart = 0;
    62→  if (dstart > len)  dstart = len;
    63→  start = dstart > INT_MAX ? INT_MAX : (int)dstart; // Rounds down
    64→
    65→  if (isnan(dend))   dend = len;
    66→  if (dend < 0)      dend += len;
    67→  if (dend < 0)      dend  = start;
    68→  end = dend > INT_MAX ? INT_MAX : (int)dend;
    69→  if (end > len)     end = len;
    70→  if (end < len)     end += end < dend ? 1 : 0; // We round start down
    71→                                                // but round end up
    72→
    73→  if (end < start) end = start;
    74→  assert(0 <= start && start <= end && end <= len);
    75→  *pstart = start;
    76→  *pend = end;
    77→  return jv_true();
    78→}
