    80→jv jv_get(jv t, jv k) {
    81→  jv v;
    82→  if (jv_get_kind(t) == JV_KIND_OBJECT && jv_get_kind(k) == JV_KIND_STRING) {
    83→    v = jv_object_get(t, k);
    84→    if (!jv_is_valid(v)) {
    85→      jv_free(v);
    86→      v = jv_null();
    87→    }
    88→  } else if (jv_get_kind(t) == JV_KIND_ARRAY && jv_get_kind(k) == JV_KIND_NUMBER) {
    89→    if (jvp_number_is_nan(k)) {
    90→      jv_free(t);
    91→      v = jv_null();
    92→    } else {
    93→      double didx = jv_number_value(k);
    94→      if (didx < INT_MIN) didx = INT_MIN;
    95→      if (didx > INT_MAX) didx = INT_MAX;
    96→      int idx = (int)didx;
    97→      if (idx < 0)
    98→        idx += jv_array_length(jv_copy(t));
    99→      v = jv_array_get(t, idx);
   100→      if (!jv_is_valid(v)) {
   101→        jv_free(v);
   102→        v = jv_null();
   103→      }
   104→    }
   105→    jv_free(k);
   106→  } else if (jv_get_kind(t) == JV_KIND_ARRAY && jv_get_kind(k) == JV_KIND_OBJECT) {
   107→    int start, end;
   108→    jv e = parse_slice(jv_copy(t), k, &start, &end);
   109→    if (jv_get_kind(e) == JV_KIND_TRUE) {
   110→      v = jv_array_slice(t, start, end);
   111→    } else {
   112→      jv_free(t);
   113→      v = e;
   114→    }
   115→  } else if (jv_get_kind(t) == JV_KIND_STRING && jv_get_kind(k) == JV_KIND_OBJECT) {
   116→    int start, end;
   117→    jv e = parse_slice(jv_copy(t), k, &start, &end);
   118→    if (jv_get_kind(e) == JV_KIND_TRUE) {
   119→      v = jv_string_slice(t, start, end);
   120→    } else {
   121→      jv_free(t);
   122→      v = e;
   123→    }
   124→  } else if (jv_get_kind(t) == JV_KIND_ARRAY && jv_get_kind(k) == JV_KIND_ARRAY) {
   125→    v = jv_array_indexes(t, k);
   126→  } else if (jv_get_kind(t) == JV_KIND_NULL &&
   127→             (jv_get_kind(k) == JV_KIND_STRING ||
   128→              jv_get_kind(k) == JV_KIND_NUMBER ||
   129→              jv_get_kind(k) == JV_KIND_OBJECT)) {
   130→    jv_free(t);
   131→    jv_free(k);
   132→    v = jv_null();
   133→  } else {
   134→    char errbuf[30];
   135→    v = jv_invalid_with_msg(jv_string_fmt(
   136→          "Cannot index %s with %s (%s)",
   137→          jv_kind_name(jv_get_kind(t)),
   138→          jv_kind_name(jv_get_kind(k)),
   139→          jv_dump_string_trunc(jv_copy(k), errbuf, sizeof(errbuf))));
   140→    jv_free(t);
   141→    jv_free(k);
   142→  }
   143→  return v;
   144→}
