   146→jv jv_set(jv t, jv k, jv v) {
   147→  if (!jv_is_valid(v)) {
   148→    jv_free(t);
   149→    jv_free(k);
   150→    return v;
   151→  }
   152→  int isnull = jv_get_kind(t) == JV_KIND_NULL;
   153→  if (jv_get_kind(k) == JV_KIND_STRING &&
   154→      (jv_get_kind(t) == JV_KIND_OBJECT || isnull)) {
   155→    if (isnull) t = jv_object();
   156→    t = jv_object_set(t, k, v);
   157→  } else if (jv_get_kind(k) == JV_KIND_NUMBER &&
   158→             (jv_get_kind(t) == JV_KIND_ARRAY || isnull)) {
   159→    if (jvp_number_is_nan(k)) {
   160→      jv_free(t);
   161→      jv_free(k);
   162→      jv_free(v);
   163→      t = jv_invalid_with_msg(jv_string("Cannot set array element at NaN index"));
   164→    } else {
   165→      double didx = jv_number_value(k);
   166→      if (didx < INT_MIN) didx = INT_MIN;
   167→      if (didx > INT_MAX) didx = INT_MAX;
   168→      if (isnull) t = jv_array();
   169→      t = jv_array_set(t, (int)didx, v);
   170→      jv_free(k);
   171→    }
   172→  } else if (jv_get_kind(k) == JV_KIND_OBJECT &&
   173→             (jv_get_kind(t) == JV_KIND_ARRAY || isnull)) {
   174→    if (isnull) t = jv_array();
   175→    int start, end;
   176→    jv e = parse_slice(jv_copy(t), k, &start, &end);
   177→    if (jv_get_kind(e) == JV_KIND_TRUE) {
   178→      if (jv_get_kind(v) == JV_KIND_ARRAY) {
   179→        int array_len = jv_array_length(jv_copy(t));
   180→        assert(0 <= start && start <= end && end <= array_len);
   181→        int slice_len = end - start;
   182→        int insert_len = jv_array_length(jv_copy(v));
   183→        if (slice_len < insert_len) {
   184→          // array is growing
   185→          int shift = insert_len - slice_len;
   186→          for (int i = array_len - 1; i >= end && jv_is_valid(t); i--) {
   187→            t = jv_array_set(t, i + shift, jv_array_get(jv_copy(t), i));
   188→          }
   189→        } else if (slice_len > insert_len) {
   190→          // array is shrinking
   191→          int shift = slice_len - insert_len;
   192→          for (int i = end; i < array_len && jv_is_valid(t); i++) {
   193→            t = jv_array_set(t, i - shift, jv_array_get(jv_copy(t), i));
   194→          }
   195→          if (jv_is_valid(t))
   196→            t = jv_array_slice(t, 0, array_len - shift);
   197→        }
   198→        for (int i = 0; i < insert_len && jv_is_valid(t); i++) {
   199→          t = jv_array_set(t, start + i, jv_array_get(jv_copy(v), i));
   200→        }
   201→        jv_free(v);
   202→      } else {
   203→        jv_free(t);
   204→        jv_free(v);
   205→        t = jv_invalid_with_msg(jv_string_fmt("A slice of an array can only be assigned another array"));
   206→      }
   207→    } else {
   208→      jv_free(t);
   209→      jv_free(v);
   210→      t = e;
   211→    }
   212→  } else if (jv_get_kind(k) == JV_KIND_OBJECT && jv_get_kind(t) == JV_KIND_STRING) {
   213→    jv_free(t);
   214→    jv_free(k);
   215→    jv_free(v);
   216→    /* Well, why not?  We should implement this... */
   217→    t = jv_invalid_with_msg(jv_string_fmt("Cannot update string slices"));
   218→  } else {
   219→    jv err = jv_invalid_with_msg(jv_string_fmt("Cannot update field at %s index of %s",
   220→                                               jv_kind_name(jv_get_kind(k)),
   221→                                               jv_kind_name(jv_get_kind(t))));
   222→    jv_free(t);
   223→    jv_free(k);
   224→    jv_free(v);
   225→    t = err;
   226→  }
   227→  return t;
   228→}
