   230→jv jv_has(jv t, jv k) {
   231→  assert(jv_is_valid(t));
   232→  assert(jv_is_valid(k));
   233→  jv ret;
   234→  if (jv_get_kind(t) == JV_KIND_NULL) {
   235→    jv_free(t);
   236→    jv_free(k);
   237→    ret = jv_false();
   238→  } else if (jv_get_kind(t) == JV_KIND_OBJECT &&
   239→             jv_get_kind(k) == JV_KIND_STRING) {
   240→    jv elem = jv_object_get(t, k);
   241→    ret = jv_bool(jv_is_valid(elem));
   242→    jv_free(elem);
   243→  } else if (jv_get_kind(t) == JV_KIND_ARRAY &&
   244→             jv_get_kind(k) == JV_KIND_NUMBER) {
   245→    if (jvp_number_is_nan(k)) {
   246→      jv_free(t);
   247→      ret = jv_false();
   248→    } else {
   249→      jv elem = jv_array_get(t, (int)jv_number_value(k));
   250→      ret = jv_bool(jv_is_valid(elem));
   251→      jv_free(elem);
   252→    }
   253→    jv_free(k);
   254→  } else {
   255→    ret = jv_invalid_with_msg(jv_string_fmt("Cannot check whether %s has a %s key",
   256→                                            jv_kind_name(jv_get_kind(t)),
   257→                                            jv_kind_name(jv_get_kind(k))));
   258→    jv_free(t);
   259→    jv_free(k);
   260→  }
   261→  return ret;
   262→}
