   264→// assumes keys is a sorted array
   265→static jv jv_dels(jv t, jv keys) {
   266→  assert(jv_get_kind(keys) == JV_KIND_ARRAY);
   267→  assert(jv_is_valid(t));
   268→
   269→  if (jv_get_kind(t) == JV_KIND_NULL || jv_array_length(jv_copy(keys)) == 0) {
   270→    // no change
   271→  } else if (jv_get_kind(t) == JV_KIND_ARRAY) {
   272→    // extract slices, they must be handled differently
   273→    jv neg_keys = jv_array();
   274→    jv nonneg_keys = jv_array();
   275→    jv new_array = jv_array();
   276→    jv starts = jv_array(), ends = jv_array();
   277→    jv_array_foreach(keys, i, key) {
   278→      if (jv_get_kind(key) == JV_KIND_NUMBER) {
   279→        if (jv_number_value(key) < 0) {
   280→          neg_keys = jv_array_append(neg_keys, key);
   281→        } else {
   282→          nonneg_keys = jv_array_append(nonneg_keys, key);
   283→        }
   284→      } else if (jv_get_kind(key) == JV_KIND_OBJECT) {
   285→        int start, end;
   286→        jv e = parse_slice(jv_copy(t), key, &start, &end);
   287→        if (jv_get_kind(e) == JV_KIND_TRUE) {
   288→          starts = jv_array_append(starts, jv_number(start));
   289→          ends = jv_array_append(ends, jv_number(end));
   290→        } else {
   291→          jv_free(new_array);
   292→          new_array = e;
   293→          goto arr_out;
   294→        }
   295→      } else {
   296→        jv_free(new_array);
   297→        new_array = jv_invalid_with_msg(jv_string_fmt("Cannot delete %s element of array",
   298→                                                      jv_kind_name(jv_get_kind(key))));
   299→        jv_free(key);
   300→        goto arr_out;
   301→      }
   302→    }
   303→
   304→    int neg_idx = 0;
   305→    int nonneg_idx = 0;
   306→    int len = jv_array_length(jv_copy(t));
   307→    for (int i = 0; i < len; ++i) {
   308→      int del = 0;
   309→      while (neg_idx < jv_array_length(jv_copy(neg_keys))) {
   310→        int delidx = len + (int)jv_number_get_value_and_consume(jv_array_get(jv_copy(neg_keys), neg_idx));
   311→        if (i == delidx) {
   312→          del = 1;
   313→        }
   314→        if (i < delidx) {
   315→          break;
   316→        }
   317→        neg_idx++;
   318→      }
   319→      while (nonneg_idx < jv_array_length(jv_copy(nonneg_keys))) {
   320→        int delidx = (int)jv_number_get_value_and_consume(jv_array_get(jv_copy(nonneg_keys), nonneg_idx));
   321→        if (i == delidx) {
   322→          del = 1;
   323→        }
   324→        if (i < delidx) {
   325→          break;
   326→        }
   327→        nonneg_idx++;
   328→      }
   329→      for (int sidx=0; !del && sidx<jv_array_length(jv_copy(starts)); sidx++) {
   330→        if ((int)jv_number_get_value_and_consume(jv_array_get(jv_copy(starts), sidx)) <= i &&
   331→            i < (int)jv_number_get_value_and_consume(jv_array_get(jv_copy(ends), sidx))) {
   332→          del = 1;
   333→        }
   334→      }
   335→      if (!del)
   336→        new_array = jv_array_append(new_array, jv_array_get(jv_copy(t), i));
   337→    }
   338→  arr_out:
   339→    jv_free(neg_keys);
   340→    jv_free(nonneg_keys);
   341→    jv_free(starts);
   342→    jv_free(ends);
   343→    jv_free(t);
   344→    t = new_array;
   345→  } else if (jv_get_kind(t) == JV_KIND_OBJECT) {
   346→    jv_array_foreach(keys, i, k) {
   347→      if (jv_get_kind(k) != JV_KIND_STRING) {
   348→        jv_free(t);
   349→        t = jv_invalid_with_msg(jv_string_fmt("Cannot delete %s field of object",
   350→                                              jv_kind_name(jv_get_kind(k))));
   351→        jv_free(k);
   352→        break;
   353→      }
   354→      t = jv_object_delete(t, k);
   355→    }
   356→  } else {
   357→    jv err = jv_invalid_with_msg(jv_string_fmt("Cannot delete fields from %s",
   358→                                               jv_kind_name(jv_get_kind(t))));
   359→    jv_free(t);
   360→    t = err;
   361→  }
   362→  jv_free(keys);
   363→  return t;
   364→}
