   366→jv jv_setpath(jv root, jv path, jv value) {
   367→  if (jv_get_kind(path) != JV_KIND_ARRAY) {
   368→    jv_free(value);
   369→    jv_free(root);
   370→    jv_free(path);
   371→    return jv_invalid_with_msg(jv_string("Path must be specified as an array"));
   372→  }
   373→  if (!jv_is_valid(root)){
   374→    jv_free(value);
   375→    jv_free(path);
   376→    return root;
   377→  }
   378→  if (jv_array_length(jv_copy(path)) == 0) {
   379→    jv_free(path);
   380→    jv_free(root);
   381→    return value;
   382→  }
   383→  jv pathcurr = jv_array_get(jv_copy(path), 0);
   384→  jv pathrest = jv_array_slice(path, 1, jv_array_length(jv_copy(path)));
   385→
   386→  /*
   387→   * We need to be careful not to make extra copies since that leads to
   388→   * quadratic behavior (e.g., when growing large data structures in a
   389→   * reduction with `setpath/2`, i.e., with `|=`.
   390→   */
   391→  if (jv_get_kind(pathcurr) == JV_KIND_OBJECT) {
   392→    // Assignment to slice -- dunno yet how to avoid the extra copy
   393→    return jv_set(root, pathcurr,
   394→                  jv_setpath(jv_get(jv_copy(root), jv_copy(pathcurr)), pathrest, value));
   395→  }
   396→
   397→  jv subroot = jv_get(jv_copy(root), jv_copy(pathcurr));
   398→  if (!jv_is_valid(subroot)) {
   399→    jv_free(root);
   400→    jv_free(pathcurr);
   401→    jv_free(pathrest);
   402→    jv_free(value);
   403→    return subroot;
   404→  }
   405→
   406→  // To avoid the extra copy we drop the reference from `root` by setting that
   407→  // to null first.
   408→  root = jv_set(root, jv_copy(pathcurr), jv_null());
   409→  if (!jv_is_valid(root)) {
   410→    jv_free(subroot);
   411→    jv_free(pathcurr);
   412→    jv_free(pathrest);
   413→    jv_free(value);
   414→    return root;
   415→  }
   416→  return jv_set(root, pathcurr, jv_setpath(subroot, pathrest, value));
   417→}
