   419→jv jv_getpath(jv root, jv path) {
   420→  if (jv_get_kind(path) != JV_KIND_ARRAY) {
   421→    jv_free(root);
   422→    jv_free(path);
   423→    return jv_invalid_with_msg(jv_string("Path must be specified as an array"));
   424→  }
   425→  if (!jv_is_valid(root)) {
   426→    jv_free(path);
   427→    return root;
   428→  }
   429→  if (jv_array_length(jv_copy(path)) == 0) {
   430→    jv_free(path);
   431→    return root;
   432→  }
   433→  jv pathcurr = jv_array_get(jv_copy(path), 0);
   434→  jv pathrest = jv_array_slice(path, 1, jv_array_length(jv_copy(path)));
   435→  return jv_getpath(jv_get(root, pathcurr), pathrest);
   436→}
