   438→// assumes paths is a sorted array of arrays
   439→static jv delpaths_sorted(jv object, jv paths, int start) {
   440→  jv delkeys = jv_array();
   441→  for (int i=0; i<jv_array_length(jv_copy(paths));) {
   442→    int j = i;
   443→    assert(jv_array_length(jv_array_get(jv_copy(paths), i)) > start);
   444→    int delkey = jv_array_length(jv_array_get(jv_copy(paths), i)) == start + 1;
   445→    jv key = jv_array_get(jv_array_get(jv_copy(paths), i), start);
   446→    while (j < jv_array_length(jv_copy(paths)) &&
   447→           jv_equal(jv_copy(key), jv_array_get(jv_array_get(jv_copy(paths), j), start)))
   448→      j++;
   449→    // if i <= entry < j, then entry starts with key
   450→    if (delkey) {
   451→      // deleting this entire key, we don't care about any more specific deletions
   452→      delkeys = jv_array_append(delkeys, key);
   453→    } else {
   454→      // deleting certain sub-parts of this key
   455→      jv subobject = jv_get(jv_copy(object), jv_copy(key));
   456→      if (!jv_is_valid(subobject)) {
   457→        jv_free(key);
   458→        jv_free(object);
   459→        object = subobject;
   460→        break;
   461→      } else if (jv_get_kind(subobject) == JV_KIND_NULL) {
   462→        jv_free(key);
   463→        jv_free(subobject);
   464→      } else {
   465→        jv newsubobject = delpaths_sorted(subobject, jv_array_slice(jv_copy(paths), i, j), start+1);
   466→        if (!jv_is_valid(newsubobject)) {
   467→          jv_free(key);
   468→          jv_free(object);
   469→          object = newsubobject;
   470→          break;
   471→        }
   472→        object = jv_set(object, key, newsubobject);
   473→      }
